import { createAgent } from '@flue/runtime'
import type { AgentRouteHandler } from '@flue/runtime'
import {
  browserClick,
  browserGoto,
  browserSnapshot,
  browserType,
} from '../tools/browser.ts'

export const route: AgentRouteHandler = async (_c, next) => next()

export default createAgent(() => ({
  model: 'anthropic/claude-sonnet-4-6',
  instructions: `
    You are a browser-using agent. Open pages with browser_goto, see them with
    browser_snapshot, and act with browser_click / browser_type using selectors
    from the latest snapshot. Always re-snapshot after navigation or a change,
    and never guess selectors. Report the result when the task is done.
  `,
  tools: [browserGoto, browserSnapshot, browserClick, browserType],
}))

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { getPage, snapshot } from '../lib/browser.ts'

export const browserGoto = defineTool({
  name: 'browser_goto',
  description: 'Navigates the browser to a URL and returns a snapshot of the page.',
  parameters: v.object({ url: v.string() }),
  execute: async ({ url }) => {
    const page = await getPage()
    await page.goto(url, { waitUntil: 'domcontentloaded' })
    return JSON.stringify(await snapshot(page))
  },
})

export const browserSnapshot = defineTool({
  name: 'browser_snapshot',
  description:
    'Returns the current page snapshot: title, URL, visible text, and interactive elements with selectors.',
  parameters: v.object({}),
  execute: async () => {
    const page = await getPage()
    return JSON.stringify(await snapshot(page))
  },
})

export const browserClick = defineTool({
  name: 'browser_click',
  description:
    'Clicks the element matching the selector (from a snapshot) and returns the resulting page snapshot.',
  parameters: v.object({ selector: v.string() }),
  execute: async ({ selector }) => {
    const page = await getPage()
    await page.click(selector)
    await page.waitForLoadState('domcontentloaded').catch(() => {})
    return JSON.stringify(await snapshot(page))
  },
})

export const browserType = defineTool({
  name: 'browser_type',
  description:
    'Types text into the input matching the selector (optionally pressing Enter), then returns a snapshot.',
  parameters: v.object({
    selector: v.string(),
    text: v.string(),
    submit: v.optional(v.boolean(), false),
  }),
  execute: async ({ selector, text, submit }) => {
    const page = await getPage()
    await page.fill(selector, text)
    if (submit) {
      await page.press(selector, 'Enter')
      await page.waitForLoadState('domcontentloaded').catch(() => {})
    }
    return JSON.stringify(await snapshot(page))
  },
})

import { type Browser, chromium, type Page } from 'playwright'

let browser: Browser | null = null
let page: Page | null = null

/**
 * Resolves the CDP endpoint, preferring Bright Data's Browser API — a fully
 * managed, anti-bot-resistant remote Chromium with no local infra to run.
 * Set BRIGHTDATA_BROWSER_AUTH to your zone "username:password", or point
 * BROWSER_CDP_URL at any other CDP endpoint. Falls back to local Chromium.
 */
function cdpEndpoint(): string | undefined {
  if (process.env.BROWSER_CDP_URL) return process.env.BROWSER_CDP_URL
  const auth = process.env.BRIGHTDATA_BROWSER_AUTH
  return auth ? `wss://${auth}@brd.superproxy.io:9222` : undefined
}

/** Returns a shared page, launching a browser on first use. */
export async function getPage(): Promise<Page> {
  if (!browser) {
    const cdpUrl = cdpEndpoint()
    browser = cdpUrl
      ? await chromium.connectOverCDP(cdpUrl)
      : await chromium.launch({ headless: process.env.BROWSER_HEADLESS !== 'false' })
  }
  if (!page) {
    page = await browser.newPage()
  }
  return page
}

/** Captures a lightweight snapshot: page text plus interactive elements + selectors. */
export async function snapshot(page: Page) {
  const elements = await page.$$eval(
    'a, button, input, textarea, select, [role="button"]',
    (nodes) =>
      nodes.slice(0, 60).map((node, index) => {
        const el = node as HTMLElement
        const tag = el.tagName.toLowerCase()
        const label =
          el.getAttribute('aria-label') ||
          el.getAttribute('placeholder') ||
          el.textContent?.trim().slice(0, 80) ||
          el.getAttribute('name') ||
          ''
        return { index, tag, label, selector: `${tag}:nth-of-type(${index + 1})` }
      })
  )
  return {
    url: page.url(),
    title: await page.title(),
    text: (await page.evaluate(() => document.body.innerText)).slice(0, 4000),
    elements,
  }
}
